fixed_code:
fn main() {
    use std::path::Path;

    let base = Path::new("/home/user");
    let file = "report.txt";
    if let Some(full_path) = base.join(file).to_str() {
        println!("Full path: {}", full_path);
    } else {
        eprintln!("Invalid UTF-8 or other error converting to string");
    }
}

